// ---------------------------------------------------------------------------
// Import list builder
// ---------------------------------------------------------------------------
function buildImports(queries) {
    const needed = new Set(['changeRecordsToZSets', 'applyZSet', 'synthDelta']);
    for (const q of queries) {
        for (const step of q.pipeline) {
            switch (step.kind) {
                case 'filter':
                    needed.add('FilterOp');
                    break;
                case 'project':
                    needed.add('ProjectOp');
                    break;
                case 'join':
                    needed.add('JoinOp');
                    break;
                case 'aggregate':
                    if (step.op === 'count')
                        needed.add('CountOp');
                    else if (step.op === 'sum')
                        needed.add('SumOp');
                    else
                        needed.add('MinMaxOp');
                    break;
                case 'sort':
                    needed.add('OrderByLimitOp');
                    break;
            }
        }
    }
    return Array.from(needed).sort();
}
// ---------------------------------------------------------------------------
// Table / State / Handler (reuse patterns from emitter.ts)
