        lines.push(`  if (${stateDrivenParts.join(' || ')}) {`);
        if (debug)
            lines.push(`    __ely_dbg('query:full-recompute', ${JSON.stringify(query.name)});`);
        // Optimization: for a pure-aggregate query (aggregate is the first/only pipeline step),
        // loadRows() does the full recompute AND syncs operator state in a single O(K) pass —
        // no wrapper-object allocation, no separate _full_xxx() call needed.
