        const stmts = [];
        while (!this.check(TokenKind.Dedent) && !this.check(TokenKind.EOF)) {
            stmts.push(this.parseStmt());
            this.skipNewlines();
        }
        this.expect(TokenKind.Dedent);
        return stmts;
